dtsPropsFor.Badge:
/** Badge contents — short status or category text. */
children: React.ReactNode;
/** Color tone; maps to a soft-background pairing. Default "neutral". */
tone?: "garnet" | "arcane" | "gold" | "vitality" | "neutral";
/** Extra classes merged onto the badge span. */
className?: string;

dtsPropsFor.Card:
/** Card body content. */
children: React.ReactNode;
/** Extra classes merged onto the card surface. */
className?: string;
/** Renders a small uppercase caption heading above the content. */
title?: string;
/** Element rendered at the right edge of the title row (e.g. a Badge). */
titleAccessory?: React.ReactNode;

dtsPropsFor.MeterBar:
/** Current value — drives the filled portion. */
current: number;
/** Maximum value. */
max: number;
/** Fill color. Default "garnet". */
tone?: "garnet" | "arcane" | "gold";
/** Accessible label; defaults to "{current} of {max}". */
label?: string;

dtsPropsFor.Modal:
/** Heading shown in the modal title bar. */
title: string;
/** Called when the user dismisses (Close, Escape, or backdrop click). */
onClose: () => void;
/** Modal body content. */
children: React.ReactNode;

dtsPropsFor.Tabs:
/** Tab items, in display order. */
tabs: { id: string; label: string; badge?: React.ReactNode }[];
/** id of the currently active tab (controlled). */
active: string;
/** Called with the id of the tab the user selects. */
onChange: (id: string) => void;
/** Extra classes merged onto the tablist track. */
className?: string;
